import React, { useState } from 'react';
import './Gallery.css';

const Lightbox = ({ isOpen, imageUrl, onClose }) => {
  if (!isOpen) return null;

  return (
    <div className="lightbox open" onClick={onClose}>
      <button className="lightbox-close" onClick={onClose}>✕</button>
      <img id="lightbox-img" src={imageUrl} alt="Gallery" />
    </div>
  );
};

const Gallery = () => {
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [selectedImage, setSelectedImage] = useState('');

  const galleryImages = [
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_23_05.jpeg',
      label: 'Shree Ram Janaki — Sanctum'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_23_04.jpeg',
      label: 'Divine Darshan'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_22_45.jpeg',
      label: 'Golden Shringar'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_22_46.jpeg',
      label: 'Kirtan Sandhya'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_22_48.jpeg',
      label: 'Temple Grounds'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_23_09.jpeg',
      label: 'Decorated Sanctum'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_23_10.jpeg',
      label: 'Temple Doorway'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_23_12.jpeg',
      label: 'Shiva Shrine'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_23_13.jpeg',
      label: 'Devotee Satsang'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_23_14.jpeg',
      label: 'Festival Celebrations'
    },
    {
      url: '/mnt/user-data/uploads/WhatsApp_Image_2026-06-06_at_16_23_15.jpeg',
      label: 'Evening Gathering'
    }
  ];

  const openLightbox = (imageUrl) => {
    setSelectedImage(imageUrl);
    setLightboxOpen(true);
  };

  const closeLightbox = () => {
    setLightboxOpen(false);
    setSelectedImage('');
  };

  // Handle escape key
  React.useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape') {
        closeLightbox();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, []);

  return (
    <>
      <div className="gallery-grid">
        {galleryImages.map((image, index) => (
          <div
            key={index}
            className="gallery-item"
            onClick={() => openLightbox(image.url)}
          >
            <img
              src={image.url}
              alt={image.label}
              onError={(e) => e.target.parentElement.style.background = 'rgba(200,146,42,0.1)'}
            />
            <div className="gallery-item-overlay">
              <span className="gallery-item-label">{image.label}</span>
            </div>
          </div>
        ))}
      </div>

      <Lightbox
        isOpen={lightboxOpen}
        imageUrl={selectedImage}
        onClose={closeLightbox}
      />
    </>
  );
};

export default Gallery;
